from jinja2 import Template

def render_kpi(ctx):
    return Template("{{ region }}: {{ median }} PEN (n={{ n }})").render(**ctx)
print(render_kpi({"region": "Lima", "median": 28.0, "n": 40}))

def render_outline(sections):
    return "\n".join("  " * (s["h"] - 1) + f"H{s['h']} {s['name']}" for s in sections)
print(render_outline([{"h": 1, "name": "Método"}, {"h": 2, "name": "Datos"}]))

def classify(chars, pages):
    return "digital" if chars / max(pages, 1) >= 20 else "needs_ocr"
print(classify(100, 1))

def pack_report(resumen, metodo, hallazgos):
    return {"resumen": resumen, "metodo": metodo, "hallazgos": hallazgos}
print(sorted(pack_report(["r"], {}, [{"id": "H1"}]).keys()))

def fmt_pen(x):
    return f"{round(float(x), 1)} PEN"
print(fmt_pen(28.04))

def a11y_min(has_h1, alts):
    return bool(has_h1) and all(len(a) > 10 for a in alts)
print(a11y_min(True, ["Barras mediana por región n en tooltip"]))
